import React from "react";
import { graphql } from "gatsby";
import Img from "gatsby-image";
import { MainHeader } from "../helpers/header";
import { Footer } from "../helpers/footer";
import styled from "styled-components";
import { media } from "../helpers/media-queries";
import { Separator } from "../components/blog/PostLink";
import PostSummary from "../components/blog/PostSummary";

export default function Template({
  data, // this prop will be injected by the GraphQL query below.
}) {
  const { markdownRemark, allMarkdownRemark } = data; // data.markdownRemark holds your post data
  const { frontmatter, html } = markdownRemark;

  const firstDifferentArticle = allMarkdownRemark.edges.find(
    (post) => post.node.id !== markdownRemark.id
  );
  const firstDifferentArticleData = firstDifferentArticle?.node;

  let featuredImgFluid = frontmatter.featuredImage.childImageSharp.fluid;

  return (
    <>
      <MainHeader dark></MainHeader>
      <BlogPostContainer className="blog-post-container">
        <div className="blog-post">
          <PostHeader>
            <PostTitle>{frontmatter.title}</PostTitle>
            <PostSubtitle>{frontmatter.subtitle}</PostSubtitle>
            <PostInfo>
              {frontmatter.author}
              <Separator />
              {frontmatter.date}
            </PostInfo>
          </PostHeader>
          <ImgStyled fluid={featuredImgFluid} />
          <PostContent
            className="blog-post-content"
            dangerouslySetInnerHTML={{ __html: html }}
          />
        </div>
      </BlogPostContainer>
      <ReadMoreContainer>
        <MoreArticlesTitle>Read more articles</MoreArticlesTitle>
        <PostSummary post={firstDifferentArticleData}></PostSummary>
      </ReadMoreContainer>
      <Footer></Footer>
    </>
  );
}

export const pageQuery = graphql`
  query ($id: String!) {
    markdownRemark(id: { eq: $id }) {
      id
      html
      frontmatter {
        date(formatString: "MMMM DD, YYYY")
        slug
        title
        subtitle
        author
        featuredImage {
          childImageSharp {
            fluid(
              maxWidth: 820
              maxHeight: 440
              quality: 100
              jpegQuality: 100
              pngQuality: 100
              pngCompressionSpeed: 1
            ) {
              ...GatsbyImageSharpFluid
            }
          }
        }
      }
    }
    allMarkdownRemark(sort: { order: DESC, fields: [frontmatter___date] }) {
      edges {
        node {
          id
          excerpt(pruneLength: 250)
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            slug
            title
            author
            featuredImage {
              childImageSharp {
                fluid(maxWidth: 260, maxHeight: 226, cropFocus: CENTER) {
                  ...GatsbyImageSharpFluid
                }
              }
            }
            featuredImageSummary {
              childImageSharp {
                fluid(
                  maxWidth: 260
                  maxHeight: 226
                  cropFocus: CENTER
                  fit: COVER
                ) {
                  ...GatsbyImageSharpFluid
                }
              }
            }
          }
        }
      }
    }
  }
`;

